import createDebug from"debug";import{data}from"./data.js";import{file}from"./file.js";import{ftp}from"./ftp.js";import{http}from"./http.js";import{https}from"./https.js";const debug=createDebug("get-uri");export const protocols={data:data,file:file,ftp:ftp,http:http,https:https};const VALID_PROTOCOLS=new Set(Object.keys(protocols));export function isValidProtocol(t){return VALID_PROTOCOLS.has(t)}export async function getUri(t,o){if(debug("getUri(%o)",t),!t)throw new TypeError('Must pass in a URI to "getUri()"');const r="string"==typeof t?new URL(t):t,e=r.protocol.replace(/:$/,"");if(!isValidProtocol(e))throw new TypeError(`Unsupported protocol "${e}" specified in URI: "${t}"`);return(0,protocols[e])(r,o)}